// Solution
function findMediaQuery(cssString) {
    const mediaQuery = cssString.match(/@media\s*\([^)]+\)/);
    if (mediaQuery) {
        const width = parseInt(mediaQuery[1].split(':')[1].trim());
        return width;
    } else {
        return -1;
    }
}

