class Solution:
    def find_media_query(self, css_string: str) -> int:
        media_query = re.search(r'@media\s*\([^)]+\)', css_string)
        if media_query:
            width = int(media_query.group(1).split(':')[1].strip())
            return width
        else:
            return -1
